using System.Threading.Channels;

/// <summary>
/// .NET 8 migration of the .NET Framework EventProcessor.
///
/// Key changes:
///   1. Channel<T> replaces ManualResetEvent + Queue + lock (thread-safe, async-ready).
///   2. CancellationToken replaces Thread.Interrupt/Abort for cooperative shutdown.
///   3. Task.Run replaces manual Thread creation.
///   4. IDisposable/IAsyncDisposable for deterministic cleanup.
///   5. All queued items are drained per wake (fixes the original race condition).
/// </summary>
public sealed class EventProcessor : IAsyncDisposable, IDisposable
{
    private readonly Channel<string> _channel;
    private readonly CancellationTokenSource _cts = new();
    private Task? _runLoop;

    public EventProcessor(int capacity = 1000)
    {
        // BoundedChannel provides backpressure; use UnboundedChannel if you
        // want the old unbounded Queue behavior (but risk OOM).
        _channel = Channel.CreateBounded<string>(new BoundedChannelOptions(capacity)
        {
            FullMode = BoundedChannelFullMode.Wait,   // block producer when full
            SingleReader = true,                       // enables internal optimizations
            SingleWriter = false
        });
    }

    public void Start()
    {
        if (_runLoop is not null)
            throw new InvalidOperationException("Already started.");

        _runLoop = Task.Run(() => RunLoopAsync(_cts.Token));
    }

    private async Task RunLoopAsync(CancellationToken ct)
    {
        try
        {
            // ReadAllAsync drains every available item — no race condition.
            await foreach (var item in _channel.Reader.ReadAllAsync(ct))
            {
                Handle(item);
            }
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Normal shutdown — drain remaining items if desired.
            while (_channel.Reader.TryRead(out var remaining))
            {
                Handle(remaining);
            }
        }
    }

    /// <summary>
    /// Enqueue an item. Waits asynchronously if the channel is full (backpressure).
    /// Throws ChannelClosedException after Stop() is called.
    /// </summary>
    public async ValueTask EnqueueAsync(string item, CancellationToken ct = default)
    {
        await _channel.Writer.WriteAsync(item, ct);
    }

    /// <summary>
    /// Synchronous overload for callers that can't use async.
    /// Returns false if the channel is full (non-blocking, no data loss).
    /// </summary>
    public bool TryEnqueue(string item)
    {
        return _channel.Writer.TryWrite(item);
    }

    public async Task StopAsync(TimeSpan? timeout = null)
    {
        timeout ??= TimeSpan.FromSeconds(5);

        // 1. Signal the channel as complete — no more writes accepted.
        _channel.Writer.TryComplete();

        // 2. Give the loop time to drain, then cancel.
        if (_runLoop is not null)
        {
            var finished = await Task.WhenAny(_runLoop, Task.Delay(timeout.Value));
            if (finished != _runLoop)
            {
                // Timed out — force cancellation (replaces Thread.Abort).
                await _cts.CancelAsync();  // .NET 8 async-safe cancel

                try { await _runLoop; }
                catch (OperationCanceledException) { }
            }
        }
    }

    private void Handle(string item)
    {
        // Your processing logic here.
        Console.WriteLine($"Processing: {item}");
    }

    // --- Disposal ---

    public async ValueTask DisposeAsync()
    {
        await StopAsync();
        _cts.Dispose();
    }

    public void Dispose()
    {
        StopAsync().GetAwaiter().GetResult();
        _cts.Dispose();
    }
}

